using System;
using System.Collections.Generic;

/// <summary>
/// Estrutura serializável (JSON) com todo o estado necessário para reconstruir
/// uma sessão de jogo: progresso do jogador, estado do mundo, variáveis globais
/// e formas desbloqueadas. Cada slot de save (1 autosave + até 30 manuais)
/// corresponde a uma instância desta classe, escrita/lida pelo SaveManager.
///
/// Não guarda referências directas a ScriptableObjects (AreaData/WorldData/
/// AnimalFormData/ItemData) — apenas os respectivos IDs, resolvidos via
/// GameDatabase ao restaurar.
///
/// Versões:
///   0 (campo ausente) — sem populacão persistida por IDs, sem EcosPerdidos.
///   1 — EcosPerdidos no fluxo de save; rescuedNpcIds por área;
///       additionalPopulation separado em VillagePopulation.
/// </summary>
[Serializable]
public class SaveData
{
    // ---------------- Versão do Save ----------------

    /// <summary>
    /// Versão da estrutura do save. Usada por <see cref="PlayerProgress.RestoreFrom"/>
    /// e <see cref="WorldState.RestoreFrom"/> para migrar saves antigos.
    /// 0 (campo ausente/padrão) = estrutura original sem IDs de NPCs resgatados.
    /// 1 = EcosPerdidos no fluxo de save; rescuedNpcIds; additionalPopulation.
    /// </summary>
    public int saveVersion;

    // ---------------- Metadados do Slot ----------------

    /// <summary>-1 = autosave; 0-29 = slot manual.</summary>
    public int slotIndex = -1;
    public bool isAutosave;

    /// <summary>Data/hora do save em formato ISO 8601 (UTC), para mostrar no menu.</summary>
    public string timestamp;

    /// <summary>Nome da cena activa no momento do save.</summary>
    public string sceneName;

    /// <summary>Posição do player no momento do save.</summary>
    public float playerPosX;
    public float playerPosY;
    public float playerPosZ;

    // ---------------- PlayerProgress ----------------

    /// <summary>True se este save foi iniciado com StartNewGamePlus (Tarefa #33).</summary>
    public bool isNewGamePlus;

    public int currentHearts = 6;
    public int maxHearts = 6;

    public int sementes;
    public int runasDeGaia;

    /// <summary>Total de Runas de Gaia recolhidas ao longo do jogo (nunca desce). "runasDeGaia" é o saldo disponível.</summary>
    public int totalRunasDeGaiaCollected;

    public int brotosDeVida;
    public int fragmentosVitais;

    /// <summary>Runas de Apolo recolhidas (0–6 — ao atingir 6 desbloqueia o Emblema de Apolo).</summary>
    public int runasDeApolo;

    /// <summary>Saldo actual de Ecos Perdidos (nunca negativo).</summary>
    public int ecosPerdidos;

    /// <summary>Total de Ecos Perdidos recolhidos ao longo do jogo (nunca desce).</summary>
    public int totalEcosPerdidosCollected;

    public List<InventoryEntry> inventory = new List<InventoryEntry>();
    public string equippedItemId;

    public List<string> collectedSpecialItemIds = new List<string>();
    public List<string> defeatedEnemyIds = new List<string>();

    /// <summary>IDs (WildMelodyData.melodyId) de Melodias Selvagens já colectadas — persistência entre sessões.</summary>
    public List<string> collectedMelodyIds = new List<string>();

    /// <summary>IDs (ChallengeDefinition.challengeId) de desafios já concluídos pelo menos uma vez (Sistema de Missões/Desafios) — controla recompensa primária única vs. secundária em repetições.</summary>
    public List<string> completedChallengeIds = new List<string>();

    /// <summary>Melhores tempos registados por desafio (apenas para desafios com 'hasTimeLimit' — usados para ranking/recordes pessoais).</summary>
    public List<ChallengeRecord> challengeRecords = new List<ChallengeRecord>();

    /// <summary>IDs persistentes (PickupBase.pickupId) de coleccionáveis do mundo já recolhidos — anti-duplicação.</summary>
    public List<string> collectedPickupIds = new List<string>();

    // ---------------- Contadores Globais de Coleccionáveis ----------------

    public int totalSementesCollected;
    public int totalFragmentosVitaisCollected;
    public int totalBrotosDeVidaCollected;
    public int totalSussurrosCollected;
    public int totalChestsOpenedGlobal;

    public List<string> freedAnimalIds = new List<string>();
    public List<string> unlockedUpgradeIds = new List<string>();

    /// <summary>IDs de upgrades "Instinto" (UpgradeData.toggleable) actualmente ligados.</summary>
    public List<string> enabledUpgradeIds = new List<string>();

    /// <summary>ID do último Refúgio Seguro (SafeHaven) usado — checkpoint.</summary>
    public string lastCheckpointId;

    public List<AreaProgress> areaProgress = new List<AreaProgress>();
    public List<string> defeatedBossWorldIds = new List<string>();
    public List<string> pendingPostBossReturnWorldIds = new List<string>();

    /// <summary>Progressão por mundo (Menu de Pausa: Progresso — Tarefa #11): se o jogador já descobriu os totais de cada mundo.</summary>
    public List<WorldProgress> worldProgress = new List<WorldProgress>();

    // ---------------- WorldState ----------------

    public TimeOfDay timeOfDay = TimeOfDay.Manha;
    public WeatherType weather = WeatherType.Limpo;

    public bool manualTimeActive;
    public TimeOfDay manualTimeSaved;

    public bool manualWeatherActive;
    public WeatherType manualWeatherSaved;

    /// <summary>WorldData.worldId / AreaData.areaId actuais (resolvidos via GameDatabase ao carregar).</summary>
    public string currentWorldId;
    public string currentAreaId;

    public List<VillagePopulation> villagePopulations = new List<VillagePopulation>();

    // ---------------- GameVariables (globais) ----------------

    public List<GameVariable> globalVariables = new List<GameVariable>();

    // ---------------- FormSwitcher ----------------

    /// <summary>AnimalFormData.formId de cada forma desbloqueada.</summary>
    public List<string> unlockedFormIds = new List<string>();

    /// <summary>AnimalFormData.formId da forma actual.</summary>
    public string currentFormId;

    // ---------------- Diário — Pistas de Missão e Rumores ----------------

    /// <summary>IDs combinados ("&lt;missionId&gt;/&lt;clueId&gt;") de pistas de missão já obtidas (Diário — sub-secção "Pistas").</summary>
    public List<string> obtainedClueIds = new List<string>();

    /// <summary>IDs (RumorData.rumorId) de rumores já ouvidos (Diário — secção "Rumores").</summary>
    public List<string> heardRumorIds = new List<string>();

    /// <summary>IDs (RumorData.rumorId) de rumores já marcados como "encontrados" (ícone de "Check").</summary>
    public List<string> foundRumorIds = new List<string>();

    // ---------------- Mapa-Múndi ----------------

    // ---------------- Snapshots Activos ----------------

    /// <summary>
    /// Snapshots de estado do player activos no momento do save (ex: missão de
    /// ladrão em curso — itens roubados ainda não devolvidos). Persistidos para
    /// que carregar um save a meio de uma sequência de roubo não apague os dados
    /// necessários para a devolução.
    ///
    /// Estrutura paralela a <see cref="PlayerProgress._snapshots"/>:
    /// cada entrada tem uma chave de texto e um <see cref="PlayerSnapshot"/>.
    /// Serializado/restaurado por <see cref="PlayerProgress.CaptureTo"/> /
    /// <see cref="PlayerProgress.RestoreFrom"/>.
    /// </summary>
    public List<SnapshotEntry> activeSnapshots = new List<SnapshotEntry>();

    /// <summary>Par (chave, snapshot) para serialização de <see cref="activeSnapshots"/>.</summary>
    [System.Serializable]
    public class SnapshotEntry
    {
        public string key;
        public PlayerSnapshot snapshot;
    }

    /// <summary>AreaData.areaId de cada área já desbloqueada no Mapa-Múndi.</summary>
    public List<string> unlockedAreaIds = new List<string>();

    /// <summary>WorldData.worldId dos mundos cujo boss já foi encontrado pelo menos uma vez (nome revelado no painel).</summary>
    public List<string> discoveredBossWorldIds = new List<string>();

    /// <summary>WorldData.worldId dos mundos cuja animação de desbloqueio da área do boss já foi reproduzida.</summary>
    public List<string> bossUnlockAnimationPlayedWorldIds = new List<string>();

    /// <summary>True quando a animação de desbloqueio da área secreta de Apolo já foi reproduzida (só acontece uma vez, ao obter o Emblema de Apolo).</summary>
    public bool apoloAreaUnlockAnimationPlayed;
}
